```json
{
  "date": "2026-06-25",
  "age_band": "0-2",
  "weather": "晴れ",
  "attendance": [{"child_id": "架空児A", "present": true, "reason": null}],
  "health_notes": null,
  "practice_record": "園庭の砂場でスコップを使った感触遊びを行った。",
  "individual_notes": [
    {"child_id": "架空児A", "observed_state": "スコップで砂をすくい感触を確かめるように繰り返し、笑顔が見られた", "tags": ["身近なものと関わり感性が育つ"]}
  ],
  "evaluation": {"child_focus": "砂の感触に繰り返し関わり、感覚的な満足を得ていた", "self_review": "スコップの数を十分用意でき、落ち着いて関われた"}
}
```

